//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (type, disGubun, codeObj, nameObj, pClose, pAllSearch) {
  var codeVal = codeObj ? codeObj.getValue() : '';
  var nameVal = nameObj ? nameObj.getValue() : '';
  if (codeObj) codeObj.setValue("");
  if (nameVal) nameObj.setValue("");
  if (type == 'CODE') {
    if (codeVal != '') scwin.f_openCommonPopUp(disGubun, codeVal, '', pClose, pAllSearch);
  } else if (type == 'NAME') {
    if (nameVal != '') scwin.f_openCommonPopUp(disGubun, '', nameVal, pClose, pAllSearch);
  }
};

//-------------------------------------------------------------------------
// 행복사
//-------------------------------------------------------------------------  
scwin.f_copyRow = function () {
  var copyRowIndex = ds_results.getRowPosition();
  var copyData = ds_results.getRowJSON(copyRowIndex);
  var addRow = ds_results.getRowCount();
  var emptyData = {
    rsltsStdDt: scwin.strCurrDate,
    selpchClsCd: '1',
    clntAmt: 0,
    clntVat: 0
  };
  copyData = addRow == 0 ? emptyData : copyData;
  copyData["dcsnYn"] = 1;
  copyData["closeYn"] = 0;
  ds_results.insertJSON(addRow, [copyData]);
  grd_results.setFocusedCell(addRow, 0);
};

//-------------------------------------------------------------------------
// 행추가
//-------------------------------------------------------------------------
scwin.f_add = function () {
  var addRowIndex = ds_results.getRowCount();
  var addData = [{
    chk: "1",
    rsltsStdDt: ed_rsltsStdDtSt.getValue(),
    selpchItemCd: ed_selpchItemCd.getValue(),
    selpchItemNm: ed_selpchItemNm.getValue(),
    sellClntNo: ed_clntNoCd.getValue(),
    sellClntNm: ed_clntNoNm.getValue(),
    selpchClsCd: acb_selpchClsCd.getValue(),
    vehclNo: ed_vehclNoNm.getValue(),
    dcsnYn: 1 //확정여부 (1.미확정)
  }];
  ds_results.insertJSON(addRowIndex, addData);
  addedRow = ds_results.getRowCount() - 1;
  grd_results.setFocusedCell(addRowIndex, 0);
};

//-------------------------------------------------------------------------
// 행삭제
//------------------------------------------------------------------------- 
scwin.f_del = function () {
  for (var i = 0; i < ds_results.getRowCount(); i++) {
    var rowStatus = ds_results.getRowStatus(i);
    if (ds_results.getCellData(i, "chk") == "1" && rowStatus == 'R') {
      ds_results.deleteRow(i);
    }
  }
};
scwin.f_undo = function () {
  var rowIndex = ds_results.getRowPosition();
  var rowStatus = ds_results.getRowStatus(rowIndex);
  if (rowStatus != 'C') {
    ds_results.undoRow(rowIndex);
  } else {
    ds_results.removeRow(rowIndex);
    if (rowIndex >= ds_results.getRowCount()) {
      rowIndex--;
    }
    grd_results.setFocusedCell(rowIndex, 0);
  }
};

//-------------------------------------------------------------------------
// 금액일괄적용
//------------------------------------------------------------------------- 
scwin.f_adaptAmt = function () {
  var clntAmt = 0;
  var clntVat = 0;
  var amtCnt = 0;
  var selpchClsCd = "";
  for (var i = 0; i < ds_results.getRowCount(); i++) {
    if (ds_results.getCellData(i, "chk") == "1") {
      //금액 
      if (Number(ds_results.getCellData(i, "clntAmt")) > 0) {
        clntAmt = Number(ds_results.getCellData(i, "clntAmt"));
        selpchClsCd = ds_results.getCellData(i, "selpchClsCd");
        amtCnt++;
      } else {
        ds_results.setCellData(i, "clntAmt", clntAmt);
      }

      //부가세
      if (Number(ds_results.getCellData(i, "clntVat")) > 0) {
        clntVat = Number(ds_results.getCellData(i, "clntVat"));
        selpchClsCd = ds_results.getCellData(i, "selpchClsCd");
        amtCnt++;
      } else {
        ds_results.setCellData(i, "clntVat", clntVat);
      }
      ds_results.setCellData(i, "selpchClsCd", selpchClsCd);
    }
  } //for

  if (amtCnt == 0) {
    $c.win.alert($p, "선택된 행들은 입력된 금액이 모두 0원 입니다.");
    return false;
  }
};

//-------------------------------------------------------------------------
// 실적일자일괄적용 (내일하지.)
//------------------------------------------------------------------------- 
scwin.f_adaptRsltsStdDt = function () {
  var chkCnt = 0;
  var rsltsStdDt = "";
  for (var i = 0; i < ds_results.getTotalCol(); i++) {
    if (ds_results.getCellData(i, "chk") == "1") {
      if (ds_results.getCellData(i, "rsltsStdDt") != "") {
        rsltsStdDt = ds_results.getCellData(i, "rsltsStdDt");
        chkCnt++;
      } else {
        ds_results.setCellData(i, "rsltsStdDt", rsltsStdDt);
      }
    }
  }
  if (chkCnt == 0) {
    $c.win.alert($p, "선택된 행이 없습니다. 일괄적용할 행들을 선택해 주십시오.");
    return false;
  }
};

