scwin.grd_results_ontextimageclick = function (rowIndex, columnIndex) {
  var row = rowIndex;
  var colId = grd_results.getColumnID(columnIndex);
  var popVal;
  if (scwin.isOpenPopup != true) {
    switch (colId) {
      case "vehclNo":
        // 차량번호
        popVal = ds_results.getCellData(row, "vehclNo").trim();
        scwin.f_openCommonPopUp(4, popVal, "", "F", "T");
        break;
      case "homeClntNm":
        // 소속거래처
        popVal = ds_results.getCellData(row, "homeClntNm").trim();
        scwin.f_openCommonPopUp(5, "", popVal, "F", "F");
        break;
      case "clntNm":
        // 매니저
        popVal = ds_results.getCellData(row, "clntNm").trim();
        scwin.f_openCommonPopUp(6, "", popVal, "F", "F");
        break;
      case "selpchItemCd":
        // 매출입항목코드
        popVal = ds_results.getCellData(row, "selpchItemCd").trim();
        scwin.f_openCommonPopUp(7, popVal, "", "F", "F");
        break;
      case "calculator":
        // 매출입항목코드
        scwin.f_goDtlAmtPop();
        break;
      default:
        break;
    }
  }
  setTimeout(function () {
    scwin.isOpenPopup = false;
  }, 100);
};
scwin.grd_results_onviewchange = function (info) {
  var row = info.rowIndex;
  var colId = info.colId;
  var popVal;
  scwin.rowPos = row;
  if (scwin.isOpenPopup != true) {
    switch (colId) {
      case "vehclNo":
        // 차량번호
        popVal = ds_results.getCellData(row, "vehclNo").trim();
        if (popVal == "") {
          ds_results.setCellData(row, "vehclNo", "");
          return;
        }
        scwin.f_openCommonPopUp(4, "", popVal, "T", "T");
        break;
      case "homeClntNm":
        // 소속거래처
        popVal = ds_results.getCellData(row, "homeClntNm").trim();
        if (popVal == "") {
          ds_results.setCellData(row, "homeClntNm", "");
          return;
        }
        scwin.f_openCommonPopUp(5, "", popVal, "T", "F");
        break;
      case "clntNm":
        // 매니저
        popVal = ds_results.getCellData(row, "clntNm").trim();
        if (popVal == "") {
          ds_results.setCellData(row, "clntNm", "");
          return;
        }
        scwin.f_openCommonPopUp(6, "", popVal, "T", "F");
        break;
      case "selpchItemCd":
        // 매출입항목코드
        // 매출입항목코드
        popVal = ds_results.getCellData(row, "selpchItemCd").trim();
        if (popVal == "") {
          ds_results.setCellData(row, "selpchItemCd", "");
          return;
        }
        scwin.f_openCommonPopUp(7, popVal, "", "T", "F");
        break;
      default:
        break;
    }
  }
  setTimeout(function () {
    scwin.isOpenPopup = false;
  }, 100);
};
scwin.grd_results_onbeforeedit = function (rowIndex, columnIndex, value) {
  var row = rowIndex;
  if (ds_results.getCellData(row, "closeYn") == '1') {
    return false;
  }
  switch (colId) {
    case "clntVat":
      if (ds_results.getCellData(row, "taxnClsCd") != '01') {
        return false;
      }
      break;
    default:
      break;
  }
};
scwin.grd_results_onafteredit = function (rowIndex, columnIndex, value) {
  var colId = grd_results.getColumnID(columnIndex);
  switch (colId) {
    case "clntAmt":
      // 금액
      var amt = Number(ds_results.getCellData(rowIndex, "clntAmt"));
      ds_results.setCellData(rowIndex, "clntAmt", amt);
      var vat = $c.num.floor($p, amt * 0.1);
      if (ds_results.getCellData(rowIndex, "taxnClsCd") == "01") {
        ds_results.setCellData(rowIndex, "clntVat", vat);
        grd_results.setFocusedCell(rowIndex, "taxnClsCd");
      }
      break;
    case "clntVat":
      // 부가세
      var amt = Number(ds_results.getCellData(rowIndex, "clntVat"));
      ds_results.setCellData(rowIndex, "clntVat", amt);
      break;
    case "selpchClsCd":
      // 지급공제구분
      var selpchClsCd = ds_results.getCellData(row, "selpchClsCd");
      if (selpchClsCd == "1") {
        if (ds_results.getCellData(rowIndex, "sellClntNo") == "") {
          $c.win.alert($p, "청구거래처를 등록해 주십시오.");
          return false;
        }
      } else if (selpchClsCd == "2") {
        if (ds_results.getCellData(rowIndex, "pchsClntNo") == "") {
          $c.win.alert($p, "정산거래처를 등록해 주십시오.");
          return false;
        }
      } else if (selpchClsCd == "3") {
        if (ds_results.getCellData(rowIndex, "pchsClntNo") == "" || ds_results.getCellData(rowIndex, "sellClntNo") == "") {
          $c.win.alert($p, "청구, 정산거래처를 모두 등록해 주십시오.");
          return false;
        }
      }
      break;
    case "deductYn":
      // 없음

      ds_cond_deductPchsAmt.setJSON({
        adptYm: ds_results.getCellData(rowIndex, "adptYm"),
        ed_vehclNoCd: ds_results.getCellData(rowIndex, "vehclNo"),
        pchsClntNo: ds_results.getCellData(rowIndex, "sellClntNo")
      });
      $c.sbm.execute($p, sbm_retrieve_deductPchsAmt);
      break;
    case "taxnClsCd":
      // 과세구분
      var amt = Number(ds_results.getCellData(rowIndex, "clntAmt"));
      var vat = $c.num.floor($p, amt * 0.1);

      // 과세구분
      if (ds_results.getCellData(rowIndex, "taxnClsCd") == "03") {
        ds_results.setCellData(rowIndex, "clntVat", 0);
      } else {
        ds_results.setCellData(rowIndex, "clntVat", vat);
      }
      break;
    case "calculator":
      // 매출입항목코드
      scwin.f_goDtlAmtPop();
      break;
    default:
      break;
  }
};
