scwin.grd_results_onfilereadend = async function (value) {
  let data = ds_results.getAllJSON();
  let newData = [];
  let excelColId = ["vehclNo", "homeClntNo", "clntNo", "rsltsStdDt", "selpchItemCd", "selpchClsCd", "clntAmt", "clntVat", "taxnClsCd", "rmk", "certiNo"];
  ds_results.removeAll();

  // 업로드 데이터 가공
  for (let i = 1; i < data.length; i++) {
    let addItem = {};
    for (let j = 0; j < excelColId.length; j++) {
      let colId = grd_results.getColumnID(j);
      addItem[excelColId[j]] = data[i][colId];
    }
    addItem['dcsnYn'] = '1';
    newData.push(addItem);
  }

  // 코드명 조회
  for (let i = 0; i < newData.length; i++) {
    ds_results.insertJSON(i, [newData[i]]);
    ds_results.setRowPosition(i);
    scwin.rowPos = i;
    await scwin.f_openCommonPopUpSync(4, "", newData[i]["vehclNo"], 'T', 'T'); //  동일차량번호 존재 문제 있음
    await scwin.f_openCommonPopUpSync(5, newData[i]["homeClntNo"], "", 'T', 'T');
    await scwin.f_openCommonPopUpSync(6, newData[i]["clntNo"], "", 'T', 'T');
    await scwin.f_openCommonPopUpSync(7, newData[i]["selpchItemCd"], "", 'T', 'T');
  }
};
